#!/usr/bin/env python3
from __future__ import annotations
import argparse,json
from stripe_test_execution_common import RUNTIME,SUPABASE_READY,now,read_json,write_json,write_report
def build():
 checkout=read_json(RUNTIME/"stripe_test_checkout_session_latest.json",{});intent=read_json(RUNTIME/"stripe_test_payment_intent_latest.json",{})
 cards=[{"id":"approve-manual-test-checkout","title":"Approve manual completion of Stripe test Checkout Session","status":"pending_Ray_review","approval_required":True,"test_mode_only":True,"exact_action":"Retrieve the gitignored URL locally and complete with Stripe test card 4242 4242 4242 4242.","external_action_performed":False,"created_at":now()},{"id":"approve-test-intent-confirm","title":"Approve Stripe test PaymentIntent confirmation using test payment method","status":"pending_Ray_review","approval_required":True,"test_mode_only":True,"exact_action":"Attach pm_card_visa and confirm only after re-verifying livemode=false.","external_action_performed":False,"created_at":now()}]
